using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability using DuckDuckGo's instant answer API.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a query. Returns relevant snippets and sources.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encodedQuery = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1&skip_disambig=1";

            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url, cancellationToken);

            var results = new List<string>();

            // Extract abstract
            var abstractText = response.GetProperty("Abstract").GetString();
            var abstractSource = response.GetProperty("AbstractSource").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] {abstractText}");
            }

            // Extract related topics
            if (response.TryGetProperty("RelatedTopics", out var relatedTopics))
            {
                foreach (var topic in relatedTopics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && !string.IsNullOrWhiteSpace(text.GetString()))
                    {
                        var firstUrl = topic.TryGetProperty("FirstURL", out var fUrl) ? fUrl.GetString() : "";
                        results.Add($"[{firstUrl}] {text.GetString()}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No results found for '{query}'. Try rephrasing your search.";
            }

            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed for '{query}': {ex.Message}. Try a different query.";
        }
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability for the research agent to track findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];

    [Description("Save a research note with a title and content. Use this to record key findings.")]
    public string AddNote(
        [Description("A short title for the note")] string title,
        [Description("The content of the note with key findings")] string content,
        [Description("The source URL or reference, if available")] string? source = null)
    {
        var note = new ResearchNote(title, content, source, DateTimeOffset.UtcNow);
        _notes.Add(note);
        return $"Note saved: '{title}' (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes to review findings before summarizing.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet. Use add_note to save research findings.";
        }

        var formatted = _notes.Select((n, i) =>
            $"[{i + 1}] {n.Title}\n    {n.Content}" +
            (n.Source is not null ? $"\n    Source: {n.Source}" : ""));

        return $"=== Research Notes ({_notes.Count} total) ===\n\n{string.Join("\n\n", formatted)}";
    }

    private sealed record ResearchNote(string Title, string Content, string? Source, DateTimeOffset Timestamp);
}

