using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Configure logging
builder.Logging.SetMinimumLevel(LogLevel.Warning);

// Register HttpClient for web search
builder.Services.AddHttpClient<WebSearchTool>();

// Register IChatClient via MEAI abstraction — API key from environment
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "OpenAI API key not configured. Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, apiKey));

var host = builder.Build();

// Instantiate tools
var httpClientFactory = host.Services.GetRequiredService<IHttpClientFactory>();
var httpClient = httpClientFactory.CreateClient(nameof(WebSearchTool));
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

// Define tool functions for the agent
var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync, "web_search",
        "Search the web for information on a query"),
    AIFunctionFactory.Create(noteTaking.AddNote, "add_note",
        "Save a research note with title, content, and optional source"),
    AIFunctionFactory.Create(noteTaking.GetNotes, "get_notes",
        "Retrieve all saved research notes"),
};

// Create agent with ChatClientAgent from Microsoft.Agents.AI
var chatClient = host.Services.GetRequiredService<IChatClient>();
var agent = new ChatClientAgent("ResearchAgent", chatClient, tools);

// Get research topic from user
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

// Build conversation with system prompt
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
