using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using Microsoft.Agents.AI;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);
builder.Logging.SetMinimumLevel(LogLevel.Warning);

// API key from environment — never hardcode secrets
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

// Pin to a specific model version to reduce behavioral drift
var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

// Register IChatClient via MEAI abstraction using OpenAI provider
var openAiChatClient = new OpenAI.Chat.ChatClient(modelId, apiKey).AsIChatClient();
builder.Services.AddChatClient(openAiChatClient);

var host = builder.Build();

// Instantiate tools
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(noteTaking.AddNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
};

// Create agent using Microsoft.Agents.AI with explicit instructions
var chatClient = host.Services.GetRequiredService<IChatClient>();
var agent = chatClient.AsAIAgent(
    instructions: """
        You are a thorough research agent. Follow this workflow:
        1. Use SearchAsync multiple times with different queries to gather information from various angles.
        2. Use AddNote to save each key finding — include a descriptive title, the information, and the source.
        3. After gathering sufficient information (at least 3-5 searches), use GetNotes to review all findings.
        4. Provide a well-structured summary with sections, citing your sources.

        Be systematic: search for definitions, recent developments, key players, and implications.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: tools);

// Get research topic from user
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();
Console.Write("Enter a research topic: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

// Create session and run agent with cost controls
var session = await agent.CreateSessionAsync(conversationId: Guid.NewGuid().ToString());

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

Console.WriteLine("[Agent is researching... This may take a moment.]\n");

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("Research complete.");

