        "Set OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

// Pin to a specific model version to reduce behavioral drift
var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

// Register IChatClient via MEAI abstraction using OpenAI provider
var openAiChatClient = new OpenAI.Chat.ChatClient(modelId, apiKey).AsIChatClient();
builder.Services.AddChatClient(openAiChatClient);

var host = builder.Build();

// Instantiate tools
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var webSearch = new WebSearchTool(httpClient);
var noteTaking = new NoteTakingTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(noteTaking.AddNote),
    AIFunctionFactory.Create(noteTaking.GetNotes),
};

