var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));
Console.WriteLine();

// Create session and run agent with cost controls
var session = await agent.CreateSessionAsync(conversationId: Guid.NewGuid().ToString());

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

Console.WriteLine("[Agent is researching... This may take a moment.]\n");

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine("Research complete.");

